## 5. 실제 Proto 예시 코드 (Maum 프로젝트 패턴 적용)

Maum 사용자 서비스에 `프로필 조회/수정` 기능을 추가하고, 기존 필드에 신규 필드를 안전하게 추가하는 전체 예시입니다.

파일 위치: `protobuf/src/main/proto/user/user_service.proto`

```protobuf
syntax = "proto3";
package user;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.user";

// ─────────────────────────────────────────
// Service 정의
// ─────────────────────────────────────────
service UserService {
  rpc GetUser(GetUserRequest)           returns (GetUserResponse);
  rpc UpdateUser(UpdateUserRequest)     returns (UpdateUserResponse);
  rpc ListUsers(ListUsersRequest)       returns (ListUsersResponse);
  rpc SearchUsers(SearchUsersRequest)   returns (SearchUsersResponse);  // v2에서 추가
}

// ─────────────────────────────────────────
// Enum 정의
// ─────────────────────────────────────────
enum UserStatus {
  USER_STATUS_UNSPECIFIED = 0;
  USER_STATUS_ACTIVE      = 1;
  USER_STATUS_DORMANT     = 2;
  USER_STATUS_BANNED      = 3;
}

enum Gender {
  GENDER_UNSPECIFIED = 0;
  GENDER_MALE        = 1;
  GENDER_FEMALE      = 2;
}

// ─────────────────────────────────────────
// 공통 메시지 (중첩 message 타입)
// ─────────────────────────────────────────
message Location {
  double latitude  = 1;
  double longitude = 2;
  string city      = 3;
}

// ─────────────────────────────────────────
// 핵심 도메인 메시지
// (v1 → v2 필드 추가 이력 포함)
// ─────────────────────────────────────────
message User {
  // [v1] 최초 출시 필드
  string     user_id     = 1;  // 사용자 UUID
  string     nickname    = 2;
  UserStatus status      = 3;  // enum 타입
  int64      created_at  = 4;  // Unix timestamp (ms)

  // [v1 삭제] phone_number, kakao_id 제거됨
  reserved 5, 6;
  reserved "phone_number", "kakao_id";

  // [v2] 신규 추가 필드 — 항상 마지막 번호 이후로 추가
  Gender          gender       = 7;            // enum 타입
  optional string bio          = 8;            // optional: null vs "" 구분
  optional int32  height       = 9;            // optional: null vs 0 구분
  repeated string photo_urls   = 10;           // repeated: 사진 목록
  optional Location location   = 11;           // optional message
  int64           updated_at   = 12;
}

// ─────────────────────────────────────────
// GetUser
// ─────────────────────────────────────────
message GetUserRequest {
  string user_id    = 1;
  string requester_id = 2;  // v2 추가: 요청자 ID (차단 여부 확인용)
}

message GetUserResponse {
  User user = 1;
}

// ─────────────────────────────────────────
// UpdateUser
// ─────────────────────────────────────────
message UpdateUserRequest {
  string          user_id   = 1;
  optional string nickname  = 2;  // optional: 변경할 필드만 전송 (null = 변경 안 함)
  optional string bio       = 3;
  optional int32  height    = 4;
  optional Gender gender    = 5;
  repeated string photo_urls = 6; // 전체 교체 방식
  optional Location location = 7;
}

message UpdateUserResponse {
  User user = 1;
}

// ─────────────────────────────────────────
// ListUsers
// ─────────────────────────────────────────
message ListUsersRequest {
  repeated string user_ids = 1;  // repeated: 다수 ID 조회
}

message ListUsersResponse {
  repeated User users = 1;
  int32         total = 2;
}

// ─────────────────────────────────────────
// SearchUsers (v2 신규 RPC)
// ─────────────────────────────────────────
message SearchUsersRequest {
  optional Gender gender     = 1;
  optional int32  min_height = 2;
  optional int32  max_height = 3;
  optional string city       = 4;
  int32           limit      = 5;
  int32           offset     = 6;
}

message SearchUsersResponse {
  repeated User users      = 1;
  int32         total      = 2;
  bool          has_next   = 3;  // 페이지네이션 여부
}
```

